import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as n,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Adding a Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/google-drive.md","filePath":"en/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"en/upload/google-drive.md"};function c(p,e,h,g,u,m){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="adding-a-google-drive-channel" tabindex="-1">Adding a Google Drive Channel <a class="header-anchor" href="#adding-a-google-drive-channel" aria-label="Permalink to &quot;Adding a Google Drive Channel&quot;">​</a></h1><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><p>Before you start, prepare these items:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Why You Need It</th></tr></thead><tbody><tr><td>A Google account</td><td>Used to access Google Cloud and authorize Google Drive</td></tr><tr><td>A Google Cloud project</td><td>Used to enable the Drive API and create OAuth credentials</td></tr><tr><td>An OAuth 2.0 client</td><td>Used by ImgBed to obtain the <code>Client ID</code>, <code>Client Secret</code>, and <code>Refresh Token</code></td></tr><tr><td>Your ImgBed domain</td><td>Used for the OAuth redirect URI. It must match the domain you actually use.</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-enable-the-google-drive-api" tabindex="-1">Step 1: Enable the Google Drive API <a class="header-anchor" href="#step-1-enable-the-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable the Google Drive API&quot;">​</a></h3><ol><li>Open Google Cloud Console.</li><li>Create a new project or select an existing one.</li><li>Go to <code>APIs &amp; Services</code>.</li><li>Click <code>Enable APIs and Services</code>.</li><li>Search for <code>Google Drive API</code>.</li><li>Open it and click enable.</li></ol><h3 id="step-2-configure-the-oauth-consent-screen" tabindex="-1">Step 2: Configure the OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-the-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure the OAuth Consent Screen&quot;">​</a></h3><ol><li>In Google Cloud, open <code>Google Auth Platform</code>.</li><li>Complete the basic <code>Branding</code> information, such as app name, support email, and developer contact email.</li><li>Open <code>Audience</code>.</li><li>For most self-hosted personal deployments, choose <code>External</code>.</li><li>If you choose <code>External</code>, add the Google account you want to authorize under <code>Test users</code>.</li><li>Open <code>Data Access</code>.</li><li>Add the required Google Drive permissions.</li></ol><h3 id="step-3-create-an-oauth-2-0-client" tabindex="-1">Step 3: Create an OAuth 2.0 Client <a class="header-anchor" href="#step-3-create-an-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: Create an OAuth 2.0 Client&quot;">​</a></h3><ol><li>In <code>Google Auth Platform</code>, open <code>Clients</code>.</li><li>Create a new client.</li><li>Set the application type to <code>Web application</code>.</li><li>Give the client a recognizable name.</li><li>For authorized JavaScript origins, enter your ImgBed URL, for example:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>For authorized redirect URIs, enter:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>After the client is created, copy these values:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-fill-in-the-google-drive-channel" tabindex="-1">Step 4: Fill in the Google Drive Channel <a class="header-anchor" href="#step-4-fill-in-the-google-drive-channel" aria-label="Permalink to &quot;Step 4: Fill in the Google Drive Channel&quot;">​</a></h2><p>In Upload Settings, choose <code>Google Drive</code> and fill in:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A name you can recognize, such as <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>The Client ID from Google Cloud</td></tr><tr><td>Client Secret</td><td>The Client Secret from Google Cloud</td></tr><tr><td>Refresh Token</td><td>Leave it empty for now. Get it in the next step.</td></tr><tr><td>Root directory</td><td>Optional. Defaults to <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-get-the-refresh-token" tabindex="-1">Step 5: Get the Refresh Token <a class="header-anchor" href="#step-5-get-the-refresh-token" aria-label="Permalink to &quot;Step 5: Get the Refresh Token&quot;">​</a></h2><ol><li>Click <code>Get Token</code>.</li><li>Choose the Google account you want to connect.</li><li>Complete the authorization prompts.</li><li>The callback page will show a <code>Refresh Token</code>.</li><li>Copy it.</li><li>Return to ImgBed and paste it into the <code>Refresh Token</code> field.</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>If you later switch Google accounts, change the OAuth client, or the old authorization expires, you do not need to delete the channel. Open the edit page and click <code>Reauthorize</code>.</p><h2 id="step-6-save-the-channel" tabindex="-1">Step 6: Save the Channel <a class="header-anchor" href="#step-6-save-the-channel" aria-label="Permalink to &quot;Step 6: Save the Channel&quot;">​</a></h2><p>After all fields are filled in, save the channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Google Cloud</span></span>
<span class="line"><span>-&gt; Create or select a project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; If Audience is External, add your Google account to Test users</span></span>
<span class="line"><span>-&gt; Create a Web application OAuth client</span></span>
<span class="line"><span>-&gt; Use https://your-domain.com/api/oauth/google/callback as the redirect URI</span></span>
<span class="line"><span>-&gt; Fill Client ID and Client Secret into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Sign in with Google and authorize</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const C=n(d,[["render",c]]);export{v as __pageData,C as default};
